1	export type ItemType = 'sword' | 'amulet' | 'staff' | 'potion' | 'rune' | 'moonstone';
2	
3	export interface Item {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	}
9	
10	export interface Customer {
11	  yearsWithMHPCO: number;
12	}
13	
14	export interface Damage {
15	  itemType: string;
16	  amount: number;
17	}
18	
19	export interface Incident {
20	  cause: string;
21	  damages: Damage[];
22	}
23	
24	export interface QuoteStep {
25	  op: 'quote';
26	  items: Item[];
27	}
28	
29	export interface ClaimStep {
30	  op: 'claim';
31	  policy: number;
32	  incident: Incident;
33	}
34	
35	export type Step = QuoteStep | ClaimStep;
36	
37	export interface Scenario {
38	  customer: Customer;
39	  steps: Step[];
40	}
41	
42	export interface QuoteResult {
43	  premium: number;
44	}
45	
46	export interface ClaimResult {
47	  payout: number;
48	  remainingCap: number;
49	}
50	
51	export type StepResult = QuoteResult | ClaimResult;
52	
53	export interface ScenarioResults {
54	  results: StepResult[];
55	}
56	
57	const MAIN_ITEMS: Record<string, { insuranceValue: number; basePremium: number }> = {
58	  sword: { insuranceValue: 1000, basePremium: 100 },
59	  amulet: { insuranceValue: 600, basePremium: 60 },
60	  staff: { insuranceValue: 800, basePremium: 80 },
61	  potion: { insuranceValue: 400, basePremium: 40 },
62	};
63	
64	const COMPONENT_TYPES = new Set(['rune', 'moonstone']);
65	const COMPONENT_VALUE = 250;
66	const COMPONENT_PREMIUM = 25;
67	const BLOCK_SIZE = 3;
68	const BLOCK_PREMIUM = 60;
69	const DEDUCTIBLE = 100;
70	const PROCESSING_FEE = 5;
71	
72	function isComponent(type: string): boolean {
73	  return COMPONENT_TYPES.has(type);
74	}
75	
76	function isKnownType(type: string): boolean {
77	  return type in MAIN_ITEMS || isComponent(type);
78	}
79	
80	function itemInsuranceValue(item: Item): number {
81	  if (isComponent(item.type)) return COMPONENT_VALUE;
82	  return MAIN_ITEMS[item.type].insuranceValue;
83	}
84	
85	function itemBasePremium(item: Item): number {
86	  if (isComponent(item.type)) return COMPONENT_PREMIUM;
87	  return MAIN_ITEMS[item.type].basePremium;
88	}
89	
90	function itemSurchargeMultiplier(item: Item): number {
91	  let m = 0;
92	  if (item.cursed) m += 0.5;
93	  if (typeof item.enchantment === 'number' && item.enchantment >= 5) m += 0.3;
94	  return m;
95	}
96	
97	interface PremiumBreakdown {
98	  policyBase: number;
99	  itemSurcharges: number;
100	  insuranceSum: number;
101	}
102	
103	function computeItemAndComponentBase(items: Item[]): PremiumBreakdown {
104	  let policyBase = 0;
105	  let itemSurcharges = 0;
106	  let insuranceSum = 0;
107	
108	  const componentCounts: Record<string, Item[]> = {};
109	  for (const item of items) {
110	    if (isComponent(item.type)) {
111	      (componentCounts[item.type] ||= []).push(item);
112	    } else {
113	      const base = itemBasePremium(item);
114	      policyBase += base;
115	      itemSurcharges += base * itemSurchargeMultiplier(item);
116	      insuranceSum += itemInsuranceValue(item);
117	    }
118	  }
119	
120	  for (const [, group] of Object.entries(componentCounts)) {
121	    const n = group.length;
122	    // Block discount applies only when the count of alike components is exactly 3.
123	    if (n === BLOCK_SIZE) {
124	      policyBase += BLOCK_PREMIUM;
125	    } else {
126	      policyBase += n * COMPONENT_PREMIUM;
127	    }
128	    insuranceSum += n * COMPONENT_VALUE;
129	    for (const item of group) {
130	      const base = itemBasePremium(item);
131	      itemSurcharges += base * itemSurchargeMultiplier(item);
132	    }
133	  }
134	
135	  return { policyBase, itemSurcharges, insuranceSum };
136	}
137	
138	export interface QuoteContext {
139	  customer: Customer;
140	  quoteIndex: number; // zero-based: 0 = first quote in scenario
141	}
142	
143	export function computeQuote(items: Item[], ctx: QuoteContext): { premium: number; insuranceSum: number } {
144	  for (const item of items) {
145	    if (!isKnownType(item.type)) {
146	      throw new Error(`Unknown item type: ${item.type}`);
147	    }
148	  }
149	
150	  const { policyBase, itemSurcharges, insuranceSum } = computeItemAndComponentBase(items);
151	
152	  let policyWideMultiplier = 1;
153	  if (ctx.customer.yearsWithMHPCO >= 2) policyWideMultiplier -= 0.2;
154	  policyWideMultiplier += 0.1; // first insurance always applies
155	  if (ctx.quoteIndex >= 1) policyWideMultiplier -= 0.15;
156	
157	  const total = policyBase * policyWideMultiplier + itemSurcharges + PROCESSING_FEE;
158	  const premium = ceilWithEpsilon(total);
159	
160	  return { premium, insuranceSum };
161	}
162	
163	const EPSILON = 1e-9;
164	
165	function ceilWithEpsilon(value: number): number {
166	  const rounded = Math.round(value);
167	  if (Math.abs(value - rounded) < EPSILON) return rounded;
168	  return Math.ceil(value);
169	}
170	
171	function floorWithEpsilon(value: number): number {
172	  const rounded = Math.round(value);
173	  if (Math.abs(value - rounded) < EPSILON) return rounded;
174	  return Math.floor(value);
175	}
176	
177	interface PolicyState {
178	  items: Item[];
179	  insuranceSum: number;
180	  cap: number;
181	  remainingCap: number;
182	}
183	
184	function payoutForDamage(item: Item, amount: number): number {
185	  const dragon = item.material === 'dragon';
186	  const highEnch = typeof item.enchantment === 'number' && item.enchantment >= 8;
187	
188	  let base: number;
189	  if (highEnch) {
190	    base = amount * 0.5;
191	  } else {
192	    base = amount;
193	  }
194	  // dragon material: full reimbursement of damage (overrides high-ench only if not also high-ench;
195	  // but spec: "both clauses apply; the 50% rule wins, then deductible")
196	  if (dragon && !highEnch) {
197	    base = amount;
198	  }
199	  return base - DEDUCTIBLE;
200	}
201	
202	export function computeClaim(policy: PolicyState, incident: Incident): { payout: number; remainingCap: number } {
203	  if (!incident.damages || incident.damages.length === 0) {
204	    return { payout: 0, remainingCap: policy.remainingCap };
205	  }
206	
207	  // Validate damages: count by itemType
208	  const policyCounts: Record<string, number> = {};
209	  for (const it of policy.items) {
210	    policyCounts[it.type] = (policyCounts[it.type] || 0) + 1;
211	  }
212	  const damageCounts: Record<string, number> = {};
213	  for (const d of incident.damages) {
214	    if (d.amount < 0) {
215	      throw new Error(`Negative damage amount: ${d.amount}`);
216	    }
217	    damageCounts[d.itemType] = (damageCounts[d.itemType] || 0) + 1;
218	  }
219	  for (const [itemType, count] of Object.entries(damageCounts)) {
220	    if (!(itemType in policyCounts) || count > policyCounts[itemType]) {
221	      throw new Error(`Damage to item not in policy or exceeds covered count: ${itemType}`);
222	    }
223	  }
224	
225	  // Build a pool of items per type to match damages to
226	  const itemPool: Record<string, Item[]> = {};
227	  for (const it of policy.items) {
228	    (itemPool[it.type] ||= []).push(it);
229	  }
230	
231	  let totalRaw = 0;
232	  for (const d of incident.damages) {
233	    // Match to an item; prefer one matching characteristics doesn't matter — each entry is independent
234	    const pool = itemPool[d.itemType];
235	    const item = pool[0]; // representative; since damage entries don't carry item attrs, use any
236	    const p = payoutForDamage(item, d.amount);
237	    totalRaw += Math.max(0, p);
238	  }
239	
240	  const finalPayoutRaw = Math.min(totalRaw, policy.remainingCap);
241	  const payout = floorWithEpsilon(finalPayoutRaw);
242	  return { payout, remainingCap: policy.remainingCap - payout };
243	}
244	
245	export function processScenario(scenario: Scenario): ScenarioResults {
246	  const results: StepResult[] = [];
247	  const policies: Record<number, PolicyState> = {};
248	  let quoteCount = 0;
249	
250	  for (let i = 0; i < scenario.steps.length; i++) {
251	    const step = scenario.steps[i];
252	    if (step.op === 'quote') {
253	      const { premium, insuranceSum } = computeQuote(step.items, {
254	        customer: scenario.customer,
255	        quoteIndex: quoteCount,
256	      });
257	      quoteCount++;
258	      const cap = insuranceSum * 2;
259	      policies[i] = {
260	        items: step.items,
261	        insuranceSum,
262	        cap,
263	        remainingCap: cap,
264	      };
265	      results.push({ premium });
266	    } else {
267	      const policy = policies[step.policy];
268	      if (!policy) {
269	        throw new Error(`Claim references unknown policy index: ${step.policy}`);
270	      }
271	      const { payout, remainingCap } = computeClaim(policy, step.incident);
272	      policy.remainingCap = remainingCap;
273	      results.push({ payout, remainingCap });
274	    }
275	  }
276	
277	  return { results };
278	}
