1	#!/usr/bin/env node
2	import { processScenario, Scenario } from './claimOffice.js';
3	
4	async function readStdin(): Promise<string> {
5	  const chunks: Buffer[] = [];
6	  for await (const chunk of process.stdin) {
7	    chunks.push(chunk as Buffer);
8	  }
9	  return Buffer.concat(chunks).toString('utf8');
10	}
11	
12	async function main() {
13	  try {
14	    const input = await readStdin();
15	    const scenario = JSON.parse(input) as Scenario;
16	    const output = processScenario(scenario);
17	    process.stdout.write(JSON.stringify(output));
18	    process.stdout.write('\n');
19	  } catch (err) {
20	    const msg = err instanceof Error ? err.message : String(err);
21	    process.stderr.write(`Error: ${msg}\n`);
22	    process.exit(1);
23	  }
24	}
25	
26	main();
