4	function quote(items: any[], years = 0, quoteIndex = 0): number {
5	  return computeQuote(items, { customer: { yearsWithMHPCO: years }, quoteIndex }).premium;
6	}
7	
8	function runScenario(scenario: Scenario) {
9	  return processScenario(scenario);
10	}
