13	  it('sword: 100 G base + 5 G fee = 105 G for newcomer first quote', () => {
14	    // 100*1.1 + 5 = 115
15	    expect(quote([{ type: 'sword' }])).toBe(115);
16	  });
17	
18	  it('amulet: 60 G base, newcomer => 60*1.1 + 5 = 71', () => {
19	    expect(quote([{ type: 'amulet' }])).toBe(71);
20	  });
21	
22	  it('staff: 80 G base, newcomer => 80*1.1 + 5 = 93', () => {
23	    expect(quote([{ type: 'staff' }])).toBe(93);
24	  });
25	
26	  it('potion: 40 G base, newcomer => 40*1.1 + 5 = 49', () => {
27	    expect(quote([{ type: 'potion' }])).toBe(49);
28	  });
29	});
