31	describe('Building block of 3 alike components (base premiums in isolation)', () => {
32	  // Test in isolation by checking policy base via direct scenarios.
33	  // We use a long-standing customer's *first* contract where loyalty (-20%) + first-ins (+10%) = -10%.
34	  // Easier: just inspect computeQuote output and subtract the known overhead.
35	
36	  it('2 runes -> 50 G base premium', () => {
37	    // No surcharges; multiplier = 1.1 for newcomer
38	    // premium = 50*1.1 + 5 = 60
39	    expect(quote([{ type: 'rune' }, { type: 'rune' }])).toBe(60);
40	  });
41	
42	  it('3 runes -> 60 G base premium (block applies)', () => {
43	    // 60*1.1 + 5 = 71
44	    expect(quote([{ type: 'rune' }, { type: 'rune' }, { type: 'rune' }])).toBe(71);
45	  });
46	
47	  it('4 runes -> 100 G base premium (no block — block requires exactly 3)', () => {
