60	describe('"Alike" components clarifying question (❓)', () => {
61	  it('2 runes + 1 moonstone -> 75 G base premium (no block: different types)', () => {
62	    // 2*25 + 25 = 75. 75*1.1 + 5 = 87.5 -> 88
